}

export async function saveFoliosToIdb(folios: Folio[]): Promise<void> {
  if (!isBrowser()) return;
  try {
    await tx("folios", "readwrite", async (t) => {
      const store = t.objectStore("folios");
      for (const f of folios) store.put(f);
