  const current = (await readFileAsJson<Suggestion[]>(SUGGESTIONS_PATH)) ?? [];
  const next = current.map((s) => (s.id === id ? { ...s, status } : s));
  await writeFileAsJson(SUGGESTIONS_PATH, next);
  markDirty();
}

