 */
function shareUrlFor(
  ownerHandle: string | null | undefined,
  slug: string,
): string | null {
  if (!ownerHandle) return null;
  const origin =
    typeof window !== "undefined" ? window.location.origin : "";
  return `${origin}/${ownerHandle}/${slug}`;
}

