import { describe, expect, test } from "bun:test";
import type { AiFeature, AiSettings } from "../types";
import { hasConfiguredAiProvider, resolveFeatureConfig } from "./ai-client";

const ALL_FEATURES: AiFeature[] = [
  "persona-feedback",
  "persona-reply",
  "persona-rewrite",
  "rubric-judge",
  "voice-narration",
  "comment-reply",
  "citation-format",
  "source-summarize",
  "source-detect-missing",
  "interview-turn",
  "dossier-check",
];

function makeSettings(overrides: Partial<AiSettings> = {}): AiSettings {
  return {
    advancedMode: false,
    providers: [
      {
        id: "provider-openai",
        name: "OpenAI",
        type: "openai",
        apiKey: "sk-test",
        defaultModel: "gpt-5.5-mini",
        availableModels: ["gpt-5.5-mini", "gpt-5.5-nano"],
      },
    ],
    defaultProviderId: "provider-openai",
    perFeature: {},
    showProviderTags: false,
    ...overrides,
  };
}

describe("ai-client provider resolution", () => {
  test("treats configured providers as active even when advancedMode is false", () => {
    const settings = makeSettings({ advancedMode: false });

    expect(hasConfiguredAiProvider(settings)).toBe(true);

    const resolved = resolveFeatureConfig(settings, "persona-feedback");
    expect(resolved?.provider.id).toBe("provider-openai");
    expect(resolved?.model).toBe("gpt-5.5-mini");
  });

  test("resolves every AI feature against the configured provider set", () => {
    const settings = makeSettings({ advancedMode: false });

    for (const feature of ALL_FEATURES) {
      const resolved = resolveFeatureConfig(settings, feature);
      expect(resolved).not.toBeNull();
      expect(resolved?.provider.id).toBe("provider-openai");
      expect(typeof resolved?.model).toBe("string");
      expect(resolved?.model.length).toBeGreaterThan(0);
    }

    expect(resolveFeatureConfig(settings, "voice-narration")?.model).toBe(
      "gpt-4o-mini-tts",
    );
  });

  test("respects per-feature provider and model overrides", () => {
    const settings = makeSettings({
      providers: [
        {
          id: "provider-openai",
          name: "OpenAI",
          type: "openai",
          apiKey: "sk-openai",
          defaultModel: "gpt-5.5-mini",
          availableModels: ["gpt-5.5-mini"],
        },
        {
          id: "provider-anthropic",
          name: "Anthropic",
          type: "anthropic",
          apiKey: "sk-anthropic",
          defaultModel: "claude-sonnet-4-6",
          availableModels: ["claude-sonnet-4-6", "claude-haiku-4-6"],
        },
      ],
      perFeature: {
        "citation-format": {
          providerId: "provider-anthropic",
          model: "claude-haiku-4-6",
          temperature: 0.1,
          maxTokens: 180,
        },
      },
    });

    const resolved = resolveFeatureConfig(settings, "citation-format");
    expect(resolved?.provider.id).toBe("provider-anthropic");
    expect(resolved?.model).toBe("claude-haiku-4-6");
    expect(resolved?.temperature).toBe(0.1);
    expect(resolved?.maxTokens).toBe(180);
  });
});

import { describe, expect, test } from "bun:test";

const CASES = [
  {
    path: "src/components/onboarding/conversational-interview.tsx",
    mustInclude: ["hasConfiguredAiProvider", "runClientInterviewTurn"],
  },
  {
    path: "src/components/personas/personas-panel.tsx",
    mustInclude: ["hasConfiguredAiProvider", "runClientAgent", "runClientRewrite"],
  },
  {
    path: "src/components/comments/comments-panel.tsx",
    mustInclude: ["hasConfiguredAiProvider", "runClientAgent"],
  },
  {
    path: "src/components/rubric/rubric-panel.tsx",
    mustInclude: ["hasConfiguredAiProvider", "runClientJudge"],
  },
  {
    path: "src/routes/refining/index.tsx",
    mustInclude: ["hasConfiguredAiProvider", "runClientDossierCheck"],
  },
  {
    path: "src/routes/apparatus/index.tsx",
    mustInclude: [
      "hasConfiguredAiProvider",
      "runClientCitationFormat",
      "runClientMissingSourceDetect",
    ],
  },
  {
    path: "src/utils/ai-orchestrator.ts",
    mustInclude: ["hasConfiguredAiProvider", "runClientAgent"],
  },
];

describe("BYOK feature coverage", () => {
  test("keeps provider-aware client paths wired across the feature surfaces", async () => {
    for (const entry of CASES) {
      const source = await Bun.file(entry.path).text();
      for (const needle of entry.mustInclude) {
        expect(source).toContain(needle);
      }
    }
  });

  test("does not reintroduce legacy advancedMode gating in the feature callers", async () => {
    for (const entry of CASES) {
      const source = await Bun.file(entry.path).text();
      expect(source).not.toContain("settings?.advancedMode && settings.providers.length > 0");
      expect(source).not.toContain("settings2?.advancedMode && settings2.providers.length > 0");
      expect(source).not.toContain("if (!settings.advancedMode || settings.providers.length === 0)");
      expect(source).not.toContain("if (settings.advancedMode && settings.providers.length > 0)");
    }
  });
});

